const body = $input.first().json.body || {};
const texto = String(body.texto || '').trim();
return [{
  json: {
    texto_entrada: 'SOLICITUD DE ESPECIFICACIÓN TÉCNICA\n\n' + texto,
    metadata: {
      nombre_proyecto: body.nombre_proyecto || 'Especificacion Tecnica',
      solicitante: 'Interfaz Web',
      fecha: new Date().toISOString().split('T')[0]
    }
  }
}];

const textoExtraido = $input.first().json.text || '';

let textoNuevo = '';
let metadata = {};
try {
  const src = $('Set - Datos Modificar').first().json;
  textoNuevo = src.texto_entrada || '';
  metadata = src.metadata || {};
} catch (e) {}

// Fallback robusto: si el texto nuevo no llegó (solo la cabecera), leerlo del webhook
const soloContenido = textoNuevo.replace(/SOLICITUD DE MODIFICACI[ÓO]N \/ AMPLIACI[ÓO]N/i, '').trim();
if (soloContenido.length < 15) {
  try {
    const body = $('Webhook - Entrada').first().json.body || {};
    if (body.texto && String(body.texto).trim()) {
      textoNuevo = 'SOLICITUD DE MODIFICACIÓN / AMPLIACIÓN\n\n' + String(body.texto).trim();
    }
  } catch (e) {}
}

let textoDocPrevio = textoExtraido
  .replace(/\x00/g, '')
  .replace(/[ \t]{2,}/g, ' ')
  .replace(/\n{3,}/g, '\n\n')
  .trim()
  .substring(0, 8000);

if (!textoDocPrevio || textoDocPrevio.length < 20) {
  textoDocPrevio = 'No se pudo extraer contenido legible del documento previo (PDF vacio o solo imagenes).';
}

return [{
  json: {
    texto_entrada: textoNuevo,
    metadata: metadata,
    texto_doc_previo: textoDocPrevio,
    nombre_doc_previo: 'Documento subido por el usuario'
  }
}];

const data = $input.first().json;

// Limitar el doc previo para que el modelo no se ancle solo en el (y por TPM)
const docPrevio = (data.texto_doc_previo || '').substring(0, 5000);

const prompt = [
  'Eres un experto en analisis de requisitos. Debes decidir si DOS documentos describen EL MISMO sistema de software o DOS sistemas DISTINTOS.',
  '',
  'CRITERIO DE DECISION (mismo_sistema):',
  '- mismo_sistema = true SOLO si ambos resuelven el MISMO problema de negocio, para el MISMO dominio y los MISMOS usuarios.',
  '  Ejemplo true: una v1 de "gestion de inventario" y una ampliacion que le añade reservas/analitica del mismo inventario.',
  '- mismo_sistema = false si pertenecen a dominios o propositos de negocio DISTINTOS, aunque compartan tecnologias o conceptos genericos (login, base de datos, pagos, etc.).',
  '  Ejemplo false: un "sistema de gestion de recursos empresariales" y una "tienda online de mascotas" son sistemas DISTINTOS.',
  '- Que ambos sean aplicaciones web, usen autenticacion o base de datos NO los hace el mismo sistema.',
  '- Si tienes dudas y los dominios de negocio no coinciden claramente, responde false.',
  '',
  '## NUEVA NECESIDAD (lo que se solicita ahora):',
  data.texto_entrada || '',
  '',
  '## DOCUMENTO PREVIO (PDF aportado por el usuario):',
  docPrevio,
  '',
  'Compara el PROPOSITO y DOMINIO de negocio de ambos. Devuelve SOLO un JSON con estos campos:',
  '- mismo_sistema: true o false',
  '- nivel_relacion: "alto", "medio", "bajo" o "ninguno"',
  '- justificacion_relacion: una frase indicando el dominio de cada uno y por que son (o no) el mismo sistema',
  '- resumen_ejecutivo: resumen del analisis',
  '- solapamientos_detectados: array de strings (vacio si son sistemas distintos)',
  '- colisiones: array de strings (vacio si son sistemas distintos)',
  '- redundancias: array de strings (vacio si son sistemas distintos)',
  '- elementos_nuevos: array de strings',
  '- recomendaciones: array de strings',
  '- impacto_estimado: "alto", "medio" o "bajo"'
].join('\n');

return [{
  json: {
    ...data,
    groq_api_key: $env.GROQ_API_KEY || '',
    groq_solap_body: {
      model: 'llama-3.3-70b-versatile',
      messages: [
        { role: 'system', content: 'Eres un analista de requisitos riguroso. Distingues si dos documentos describen el mismo sistema comparando su dominio y proposito de negocio, no solo sus tecnologias. Sistemas de dominios distintos son sistemas distintos aunque compartan conceptos genericos. Respondes SOLO con JSON valido, sin texto adicional.' },
        { role: 'user', content: prompt }
      ],
      max_tokens: 1500,
      temperature: 0.1,
      response_format: { type: 'json_object' }
    }
  }
}];

const groqResponse = $input.first().json;
let informeSolapamiento = {};

try {
  const content = groqResponse?.choices?.[0]?.message?.content || '{}';
  informeSolapamiento = JSON.parse(content);
} catch (e) {
  informeSolapamiento = { error: 'Error: ' + e.message, resumen_ejecutivo: 'Error en analisis' };
}

const prevData = $('Code - Preparar Contexto Solapamiento').first().json;

return [{
  json: {
    texto_entrada: prevData.texto_entrada,
    metadata: prevData.metadata,
    informe_solapamiento: informeSolapamiento,
    es_mismo_sistema: !(informeSolapamiento.mismo_sistema === false || informeSolapamiento.mismo_sistema === "false"),
    texto_doc_previo: prevData.texto_doc_previo || "",
    nombre_doc_previo: prevData.nombre_doc_previo || "",
    tiene_docs_previos: true
  }
}];

const src = $('Set - Datos Entrada').first().json;
return [{
  json: {
    texto_entrada: src.texto_entrada || '',
    metadata: src.metadata || {},
    informe_solapamiento: {
      resumen_ejecutivo: 'Sin documentación previa - Primera versión',
      solapamientos_detectados: [], colisiones: [], redundancias: [],
      elementos_nuevos: ['Todo el alcance es nuevo'],
      recomendaciones: ['Proceder con generación completa'],
      impacto_estimado: 'N/A'
    },
    tiene_docs_previos: false,
    texto_doc_previo: ''
  }
}];

const groqResponse = $input.first().json;
let especificacion = {};

try {
  let content = groqResponse?.choices?.[0]?.message?.content || '{}';

  // Limpiar markdown si lo hay
  content = content.replace(/^```(?:json)?\n?/i, '').replace(/\n?```$/, '').trim();

  // Eliminar caracteres de control que rompen JSON
  content = content.replace(/[\x00-\x08\x0b\x0c\x0e-\x1f]/g, '');

  const parsed = JSON.parse(content);

  // Detectar si Groq envolvió el spec en un objeto raíz (ej: { "especificacion": {...} })
  if (!parsed.requisitos_funcionales && !parsed.titulo_documento) {
    const keys = Object.keys(parsed);
    // Si hay una sola clave y su valor es un objeto, ese es el spec real
    if (keys.length === 1 && typeof parsed[keys[0]] === 'object' && !Array.isArray(parsed[keys[0]])) {
      especificacion = parsed[keys[0]];
    } else {
      // Buscar la clave que contenga requisitos_funcionales
      for (const key of keys) {
        if (parsed[key]?.requisitos_funcionales || parsed[key]?.titulo_documento) {
          especificacion = parsed[key];
          break;
        }
      }
      if (!especificacion.titulo_documento) especificacion = parsed;
    }
  } else {
    especificacion = parsed;
  }

} catch (e) {
  especificacion = {
    titulo_documento: 'Error al procesar respuesta IA',
    resumen_ejecutivo: 'Error de parseo: ' + e.message,
    requisitos_funcionales: [],
    requisitos_no_funcionales: [],
    casos_de_uso: [],
    riesgos: [],
    glosario: []
  };
}

const prevData = $('Merge - Unir Ramas A y B').first().json;

return [{
  json: {
    texto_entrada: prevData.texto_entrada,
    metadata: prevData.metadata,
    informe_solapamiento: prevData.informe_solapamiento,
    tiene_docs_previos: prevData.tiene_docs_previos,
    especificacion_borrador: especificacion
  }
}];

const data = $input.first().json;
const spec = data.especificacion_borrador || {};

// Enviamos solo un resumen compacto en vez del JSON completo para ahorrar tokens
const specResumen = {
  titulo: spec.titulo_documento || '',
  requisitos_funcionales: (spec.requisitos_funcionales || []).map(r => r.id + ': ' + r.nombre),
  requisitos_no_funcionales: (spec.requisitos_no_funcionales || []).map(r => r.id + ': ' + r.descripcion),
  casos_de_uso: (spec.casos_de_uso || []).map(c => c.id + ': ' + c.nombre),
  riesgos: (spec.riesgos || []).map(r => r.descripcion),
};

const prompt = [
  'Revisa este resumen de especificacion tecnica y devuelve mejoras concretas:',
  '',
  JSON.stringify(specResumen, null, 2),
  '',
  'Solicitud original: ' + (data.texto_entrada || '').substring(0, 500),
  '',
  'Devuelve JSON con: { puntuacion_inicial, problemas_criticos: [], mejoras_sugeridas: [], fortalezas: [], cambios_aplicados: [], puntuacion_final }'
].join('\n');

return [{
  json: {
    ...data,
    groq_api_key: $env.GROQ_API_KEY || '',
    groq_revision_body: {
      model: 'llama-3.1-8b-instant',
      messages: [
        { role: 'system', content: 'Eres un revisor experto en ingenieria de requisitos. Devuelve siempre JSON valido.' },
        { role: 'user', content: prompt }
      ],
      max_tokens: 2000,
      temperature: 0.2,
      response_format: { type: 'json_object' }
    }
  }
}];

const groqResponse = $input.first().json;
let revisionData = {};

try {
  const content = groqResponse?.choices?.[0]?.message?.content || '{}';
  revisionData = JSON.parse(content);
} catch (e) {
  revisionData = { error: 'Error: ' + e.message };
}

const prevData = $('Code - Procesar Borrador Groq').first().json;

return [{
  json: {
    texto_entrada: prevData.texto_entrada,
    metadata: prevData.metadata,
    informe_solapamiento: prevData.informe_solapamiento,
    tiene_docs_previos: prevData.tiene_docs_previos,
    especificacion_borrador: prevData.especificacion_borrador,
    revision_groq: revisionData,
    especificacion_revisada: revisionData.especificacion_mejorada || prevData.especificacion_borrador
  }
}];

const data = $input.first().json;

// spec puede venir de la revisión o del borrador directamente
let spec = data.especificacion_revisada || data.especificacion_borrador || {};

// Desenvuelve wrappers extra de Groq (ej: { "especificacion": { ... } })
if (!spec.requisitos_funcionales && !spec.titulo_documento) {
  const keys = Object.keys(spec).filter(k => typeof spec[k] === 'object' && !Array.isArray(spec[k]));
  for (const k of keys) {
    if (spec[k]?.requisitos_funcionales || spec[k]?.titulo_documento) {
      spec = spec[k];
      break;
    }
  }
}

const fecha = new Date().toISOString().split('T')[0];

// Normalizar claves de diagramas (Groq puede usar nombres distintos)
const dm = spec.diagramas_mermaid || {};
const diagramas = {
  casos_uso:       dm.casos_uso       || dm.diagrama_casos_uso       || dm.caso_de_uso       || '',
  flujo_principal: dm.flujo_principal || dm.diagrama_flujo_principal || dm.flujo             || '',
  entidad_relacion:dm.entidad_relacion|| dm.diagrama_er              || dm.er                || '',
  arquitectura:    dm.arquitectura    || dm.diagrama_arquitectura    || dm.arquitectura_sistema || ''
};

const documentoFinal = {
  titulo:                   spec.titulo_documento || 'Especificación Técnica del Sistema',
  subtitulo:                'Software Requirements Specification (SRS)',
  version:                  spec.version         || '1.0',
  fecha:                    spec.fecha           || fecha,
  estado:                   'Borrador para Revisión',
  resumen_ejecutivo:        spec.resumen_ejecutivo         || '',
  objetivo_del_documento:   spec.objetivo_del_documento    || '',
  alcance:                  spec.alcance                   || '',
  supuestos:                spec.supuestos                 || [],
  restricciones:            spec.restricciones             || [],
  requisitos_funcionales:   spec.requisitos_funcionales    || [],
  requisitos_no_funcionales:spec.requisitos_no_funcionales || [],
  requisitos_informacion:   spec.requisitos_informacion    || [],
  no_requisitos:            spec.no_requisitos             || [],
  casos_de_uso:             spec.casos_de_uso              || [],
  riesgos:                  spec.riesgos                   || [],
  glosario:                 spec.glosario                  || [],
  analisis_calidad:         spec.analisis_calidad          || [],
  matriz_trazabilidad:      spec.matriz_trazabilidad       || [],
  actores:                  spec.actores                   || [],
  relaciones_casos_uso:     spec.relaciones_casos_uso      || [],
  relaciones_entidades:     spec.relaciones_entidades      || [],
  integraciones_externas:   spec.integraciones_externas    || [],
  estudios_viabilidad:      spec.estudios_viabilidad       || [],
  estudio_alternativas:     spec.estudio_alternativas      || {},
  diagramas_mermaid:        diagramas
};

return [{
  json: {
    documento_final: documentoFinal,
    metadata:             data.metadata             || {},
    informe_solapamiento: data.informe_solapamiento || {},
    tiene_docs_previos:   data.tiene_docs_previos   || false
  }
}];

const data = $input.first().json;
const doc = data.documento_final || {};

// ── Sanitizadores ────────────────────────────────────────────────────────────
function lbl(s, max) {
  let t = String(s || '').trim();
  t = t.replace(/["'`]/g, '');
  t = t.replace(/[\[\]\{\}\(\)\|<>]/g, '');
  t = t.replace(/[;#]/g, '');
  t = t.replace(/\s+/g, ' ');
  t = t.replace(/[áàä]/gi, 'a').replace(/[éèë]/gi, 'e').replace(/[íìï]/gi, 'i')
       .replace(/[óòö]/gi, 'o').replace(/[úùü]/gi, 'u').replace(/ñ/gi, 'n');
  if (max && t.length > max) t = t.slice(0, max - 1) + '.';
  return t || 'N/A';
}
function ident(s, max) {
  let t = String(s || '').trim();
  t = t.replace(/[áàä]/gi, 'a').replace(/[éèë]/gi, 'e').replace(/[íìï]/gi, 'i')
       .replace(/[óòö]/gi, 'o').replace(/[úùü]/gi, 'u').replace(/ñ/gi, 'n');
  t = t.replace(/[^A-Za-z0-9]+/g, '_').replace(/_+/g, '_').replace(/^_|_$/g, '');
  if (max && t.length > max) t = t.slice(0, max).replace(/_$/, '');
  if (!t) t = 'campo';
  if (/^[0-9]/.test(t)) t = 'e_' + t;
  return t;
}
// Normaliza un id de caso de uso "CU-001", "cu 1", "CU1" → "CU001"
function normId(s) { return String(s || '').toUpperCase().replace(/[^A-Z0-9]/g, ''); }

// ── 1. Casos de Uso → PlantUML con actores, sistema, include y extend ────────
function buildCasosUso() {
  const cus = (doc.casos_de_uso || []).slice(0, 14);
  const sistema = lbl((doc.titulo || 'Sistema').replace(/Especificaci.n T.cnica del?/i, '').trim() || 'Sistema', 36);

  function normalizarActor(raw) {
    let a = lbl(raw || 'Usuario', 28);
    if (/^(el\s+)?sistema$|^system$|^automatic|^proceso\s+autom/i.test(a.trim())) return 'Temporizador';
    return a;
  }

  const lines = ['@startuml', 'left to right direction', 'skinparam packageStyle rectangle', 'skinparam shadowing false',
    'skinparam nodesep 45', 'skinparam ranksep 60'];

  if (cus.length === 0) {
    lines.push('actor "Usuario" as A0', 'rectangle "' + sistema + '" {', '  usecase "Caso de uso principal" as UC0', '}', 'A0 --> UC0', '@enduml');
    return lines.join('\n');
  }

  // Mapa id de caso de uso → UCi
  const cuMap = {};
  cus.forEach((cu, i) => { cuMap[normId(cu.id) || ('CU' + i)] = 'UC' + i; });

  // Relaciones include/extend normalizadas. Preferimos los campos semánticos
  // caso_base / caso_secundario; si no vienen, usamos origen/destino (retrocompat).
  const relaciones = (doc.relaciones_casos_uso || []).map(r => ({
    base: cuMap[normId(r.caso_base != null ? r.caso_base : r.origen)],
    sec:  cuMap[normId(r.caso_secundario != null ? r.caso_secundario : r.destino)],
    esExtend: /ext/i.test(r.tipo)
  })).filter(r => r.base && r.sec && r.base !== r.sec);

  // Los casos SECUNDARIOS (el incluido y el de extensión) NO se conectan a
  // actores: el actor llega a ellos a través del caso base.
  const sinActor = new Set();
  relaciones.forEach(r => sinActor.add(r.sec));

  // Registrar actores. Solo los que participan en un caso CON actor,
  // más los implicados en herencia de actores (padres/hijos).
  const actores = {};
  function regActor(nombre) { if (nombre && nombre !== 'N/A' && !(nombre in actores)) actores[nombre] = 'A' + Object.keys(actores).length; return actores[nombre]; }
  cus.forEach((cu, i) => {
    if (sinActor.has('UC' + i)) return;
    regActor(normalizarActor(cu.actor_principal));
    (cu.actores_secundarios || []).forEach(as => regActor(normalizarActor(as)));
  });
  // Herencia entre actores: un actor puede especializar a otro (hijo --|> padre)
  const herenciaPorNombre = []; // [nombreHijo, nombrePadre]
  (doc.actores || []).forEach(a => {
    if (!a || !a.hereda_de) return;
    const hijo = normalizarActor(a.nombre);
    const padre = normalizarActor(a.hereda_de);
    if (hijo && padre && hijo !== padre) { regActor(hijo); regActor(padre); herenciaPorNombre.push([hijo, padre]); }
  });

  // ── Reordenar actores para minimizar cruces visuales ────────────────────────
  // Si un actor "padre" tiene varios hijos por herencia, colocarlo AL EXTREMO
  // opuesto los deja lejos y sus lineas de asociacion/herencia cruzan por
  // encima de los demas. En su lugar, el padre se intercala ENTRE sus hijos
  // (mitad antes, mitad despues), asi cada flecha de herencia queda corta y
  // adyacente en vez de atravesar todo el diagrama.
  function ordenarParaLayout(nombresOriginal, herenciaPares) {
    const hijosDePadre = {};
    const tienePadre = new Set();
    herenciaPares.forEach(([hijo, padre]) => {
      (hijosDePadre[padre] = hijosDePadre[padre] || []).push(hijo);
      tienePadre.add(hijo);
    });
    const colocado = new Set();
    const resultado = [];
    nombresOriginal.forEach(n => {
      if (colocado.has(n)) return;
      if (hijosDePadre[n]) {
        const hijos = hijosDePadre[n].filter(h => !colocado.has(h));
        const mitad = Math.floor(hijos.length / 2);
        hijos.slice(0, mitad).forEach(h => { resultado.push(h); colocado.add(h); });
        resultado.push(n); colocado.add(n);
        hijos.slice(mitad).forEach(h => { resultado.push(h); colocado.add(h); });
      } else if (!tienePadre.has(n)) {
        resultado.push(n); colocado.add(n);
      }
      // Si "n" tiene padre y su padre aun no ha sido procesado, se omite aqui:
      // se colocara cuando el bucle llegue al padre (bloque hijosDePadre[n] de arriba).
    });
    return resultado;
  }
  const ordenActores = ordenarParaLayout(Object.keys(actores), herenciaPorNombre);

  // Declarar actores en el orden ya optimizado
  ordenActores.forEach(nombre => lines.push('actor "' + nombre + '" as ' + actores[nombre]));

  // Recuadro del sistema con los casos de uso
  lines.push('rectangle "' + sistema + '" {');
  cus.forEach((cu, i) => lines.push('  usecase "' + lbl(cu.nombre || ('Caso ' + (i + 1)), 34) + '" as UC' + i));
  lines.push('}');

  // Herencia de actores (generalización): Cliente -up-|> Usuario
  // El hint de direccion "up" favorece un trazo recto y corto en vez de
  // una curva larga que rodee otros elementos del diagrama.
  herenciaPorNombre.forEach(([hijo, padre]) => lines.push(actores[hijo] + ' -up-|> ' + actores[padre]));

  // Asociaciones actor → caso de uso (solo para casos que llevan actor)
  cus.forEach((cu, i) => {
    if (sinActor.has('UC' + i)) return;
    const ap = actores[normalizarActor(cu.actor_principal)];
    if (ap) lines.push(ap + ' --> UC' + i);
    (cu.actores_secundarios || []).forEach(as => {
      const aid = actores[normalizarActor(as)]; if (aid) lines.push(aid + ' --> UC' + i);
    });
  });

  // Relaciones include / extend con DIRECCIÓN garantizada por el código
  // (no depende de que la IA ordene bien los extremos):
  //  · include: caso BASE ──▷ caso INCLUIDO   (punta en el incluido/dependiente)
  //  · extend : caso EXTENSIÓN ──▷ caso BASE   (punta en el caso base) [opuesto]
  const vistas = new Set();
  relaciones.forEach(r => {
    const from = r.esExtend ? r.sec : r.base;
    const to   = r.esExtend ? r.base : r.sec;
    const key = from + '>' + to + (r.esExtend ? 'e' : 'i');
    if (vistas.has(key)) return; vistas.add(key);
    lines.push(from + ' .[#0f3460].> ' + to + ' : <<' + (r.esExtend ? 'extend' : 'include') + '>>');
  });

  lines.push('@enduml');
  return lines.join('\n');
}

// ── 2. Actividad UML: flujo principal + múltiples decisiones ─────────────────
function buildFlujo() {
  const cu = (doc.casos_de_uso || [])[0];
  const pasos = (cu && cu.flujo_principal && cu.flujo_principal.length)
    ? cu.flujo_principal.slice(0, 10)
    : (doc.requisitos_funcionales || []).slice(0, 6).map(r => r.nombre || r.descripcion);
  const alt = (cu && cu.flujos_alternativos && cu.flujos_alternativos.length) ? cu.flujos_alternativos.slice(0, 3) : [];

  const lines = ['@startuml', 'skinparam shadowing false', 'start'];
  if (!pasos || pasos.length === 0) { lines.push(':Proceso principal;', 'stop', '@enduml'); return lines.join('\n'); }

  // Repartir las decisiones (una por cada flujo alternativo) entre los pasos.
  // Puntos de decision equiespaciados a lo largo del flujo principal.
  const nAlt = alt.length;
  const puntos = {};
  if (nAlt > 0) {
    for (let k = 0; k < nAlt; k++) {
      const idx = Math.min(pasos.length - 1, Math.floor(((k + 1) * pasos.length) / (nAlt + 1)));
      (puntos[idx] = puntos[idx] || []).push(alt[k]);
    }
  }

  pasos.forEach((p, i) => {
    lines.push(':' + lbl(p, 48) + ';');
    if (puntos[i]) {
      puntos[i].forEach(a => {
        lines.push('if (' + lbl('Condicion en paso ' + (i + 1) + '?', 40) + ') then (excepcion)');
        lines.push('  :' + lbl(a, 48) + ';');
        lines.push('  stop');
        lines.push('else (ok)');
        lines.push('endif');
      });
    }
  });

  lines.push('stop', '@enduml');
  return lines.join('\n');
}

// ── 3. Clases UML: atributos, métodos y relaciones ricas ─────────────────────
function buildClases() {
  const ents = (doc.requisitos_informacion || []).slice(0, 10);
  const lines = ['@startuml', 'skinparam shadowing false', 'skinparam classAttributeIconSize 0'];

  if (ents.length === 0) {
    lines.push('class Entidad {', '  +id: string', '  +nombre: string', '}', '@enduml');
    return lines.join('\n');
  }

  // Mapa nombre-entidad → nombre de clase (para resolver relaciones)
  const claseDe = {};
  const ids = [];
  ents.forEach((e, i) => {
    let nombre = ident(e.entidad || ('Entidad' + i), 28);
    nombre = nombre.charAt(0).toUpperCase() + nombre.slice(1);
    if (ids.includes(nombre)) nombre = nombre + i;
    ids.push(nombre);
    claseDe[normId(e.entidad)] = nombre;
    lines.push('class ' + nombre + ' {');
    const attrs = (e.atributos && e.atributos.length ? e.atributos : ['id', 'nombre']).slice(0, 6);
    const usados = {};
    attrs.forEach(a => { let an = ident(a, 28); if (usados[an]) an = an + (usados[an]++); else usados[an] = 1; lines.push('  +' + an + ': string'); });
    const metodos = (e.metodos && e.metodos.length ? e.metodos : []).slice(0, 6);
    if (metodos.length > 0) {
      lines.push('  --');
      const um = {};
      metodos.forEach(m => { let mn = ident(String(m).replace(/\(\s*\)\s*$/, ''), 28); if (um[mn]) mn = mn + (um[mn]++); else um[mn] = 1; lines.push('  +' + mn + '()'); });
    }
    lines.push('}');
  });

  // Relaciones explícitas generadas por la IA
  const rels = doc.relaciones_entidades || [];
  let dibujadas = 0;
  rels.forEach(r => {
    const o = claseDe[normId(r.origen)];
    const d = claseDe[normId(r.destino)];
    if (!o || !d || o === d) return;
    const mo = lbl(r.mult_origen || r.cardinalidad_origen || '1', 8);
    const md = lbl(r.mult_destino || r.cardinalidad_destino || r.cardinalidad || '0..*', 8);
    const et = r.etiqueta ? ' : ' + lbl(r.etiqueta, 24) : '';
    const tipo = String(r.tipo || 'asociacion').toLowerCase();
    let linea;
    if (/herenc|generaliz|extend|hereda/.test(tipo))      linea = d + ' --|> ' + o;                       // destino hereda de origen
    else if (/composic/.test(tipo))                       linea = o + ' "' + mo + '" *-- "' + md + '" ' + d + et;
    else if (/agregac/.test(tipo))                        linea = o + ' "' + mo + '" o-- "' + md + '" ' + d + et;
    else if (/dependenc/.test(tipo))                      linea = o + ' ..> ' + d + et;
    else                                                  linea = o + ' "' + mo + '" -- "' + md + '" ' + d + et; // asociacion
    lines.push(linea);
    dibujadas++;
  });

  // Fallback: si la IA no aportó relaciones, encadenar (mejor que nada)
  if (dibujadas === 0) {
    for (let i = 0; i < ids.length - 1; i++) lines.push(ids[i] + ' "1" -- "0..*" ' + ids[i + 1]);
  }

  lines.push('@enduml');
  return lines.join('\n');
}

// ── 4. Componentes UML ───────────────────────────────────────────────────────
function buildComponentes() {
  const sistema = lbl((doc.titulo || 'Sistema').replace(/Especificaci.n T.cnica del?/i, '').trim() || 'Sistema', 30);
  const lines = ['@startuml', 'skinparam shadowing false', 'left to right direction',
    'actor "Usuario" as U',
    'component "Frontend Web" as FE',
    'component "API REST" as API',
    'component "' + sistema + '" as BL',
    'database "Base de Datos" as DB',
    'U --> FE', 'FE --> API : HTTP/JSON', 'API --> BL', 'BL --> DB : SQL'];
  // Añadir servicios externos según integraciones detectadas
  const ext = (doc.integraciones_externas || []).slice(0, 4);
  if (ext.length) {
    ext.forEach((e, i) => { lines.push('component "' + lbl(e, 26) + '" as EXT' + i); lines.push('BL --> EXT' + i); });
  } else {
    lines.push('component "Servicios Externos" as EXT', 'BL --> EXT');
  }
  lines.push('@enduml');
  return lines.join('\n');
}

